<!DOCTYPE html>
<html>
<head>
  <style>
    body {
      font-family: sans-serif;
      text-align: center;
    }
    #maze {
      border: 1px solid black;
      margin-top: 20px;
    }
    #completed, #timer {
      font-size: 1.5em;
      margin: 10px;
