<body>
  <div id="completed">0/24</div>
  <div id="timer">0</div>
  <button id="reset">Reset</button>
  <canvas id="maze" width="600" height="600"></canvas>

  <script>
    (function() {
      const PRNG = function(seed) {
        let x = seed;
        return () => {
          x ^= x << 13;
          x ^= x >>> 17;
          x ^= x << 5;
          return (x >>> 0) / 4294967296;
        };
      };

      const generateMaze = function(rows, cols, prng) {
        const maze = [];
        for (let r = 0; r < rows; r++) {
          maze[r] = [];
          for (let c = 0; c < cols; c++) {
            maze[r][c] = { n: true, e: true, s: true, w: true };
          }
        }

        const visited = new Set();
        function carve(r, c) {
          visited.add(`${r},${c}`);
          let dirs = ['n', 'e', 's', 'w'];
          while (dirs.length > 0) {
            let i = Math.floor(prng() * dirs.length);
            let dir = dirs.splice(i, 1)[0];

            let nr = r, nc = c;
            switch(dir) {
              case 'n': nr -= 1; break;
              case 'e': nc += 1; break;
              case 's': nr += 1; break;
              case 'w': nc -= 1; break;
            }

            if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;

            if (!visited.has(`${nr},${nc}`)) {
              maze[r][c][dir] = false;
              const oppositeDir = { n: 's', e: 'w', s: 'n', w: 'e' }[dir];
              maze[nr][nc][oppositeDir] = false;

              carve(nr, nc);
            }
          }
        }

        let startR = Math.floor(prng() * rows);
        let startC = Math.floor(prng() * cols);
        carve(startR, startC);
        return maze;
      };

      const Bot = function(mazeSize, spawnCell, directionOrder) {
        this.path = [ { ...spawnCell } ];
        this.deadEnds = [];
        this.currentCell = { ...spawnCell };
        this.stack = [ { ...spawnCell } ];
        this.visited = new Set([ `${spawnCell.r},${spawnCell.c}` ]);
        this.directionOrder = directionOrder;
        this.finishedTick = null;
      };

      Bot.prototype.update = function(maze, exitCell, currentTick) {
        if (this.finishedTick !== null) return;

        const cr = this.currentCell.r;
        const cc = this.currentCell.c;
        let moved = false;

        for (let dir of this.directionOrder) {
          let nr = cr, nc = cc;
          switch(dir) {
            case 'n': nr -= 1; break;
            case 'e': nc += 1; break;
            case 's': nr += 1; break;
            case 'w': nc -= 1; break;
          }

          if (nr < 0 || nr >= maze.length || nc < 0 || nc >= maze[0].length) continue;

          const walls = maze[cr][cc];
          let canMove = false;
          switch(dir) {
            case 'n': canMove = !walls.n; break;
            case 'e': canMove = !walls.e; break;
            case 's': canMove = !walls.s; break;
            case 'w': canMove = !walls.w; break;
          }

          if (!canMove) continue;

          const nextKey = `${nr},${nc}`;
          if (this.visited.has(nextKey)) continue;

          this.currentCell = { r: nr, c: nc };
          this.path.push({ ...this.currentCell });
          this.stack.push(this.currentCell);
          this.visited.add(nextKey);

          moved = true;

          if (nr === exitCell.r && nc === exitCell.c) {
            this.finishedTick = currentTick;
          }

          break;
        }

        if (!moved && this.stack.length > 1) {
          const prevCell = this.stack[this.stack.length - 2];
          this.currentCell = { ...prevCell };
          this.stack.pop();
          const poppedCell = this.stack[this.stack.length - 1];
          this.deadEnds.push(poppedCell);
        }
      };

      window.game = {
        elapsed: 0,
        size: { rows: 0, cols: 0 },
        spawn: { r: 0, c: 0 },
        exit: { r: 0, c: 0 },
        bots: [],
        mazeData: null,

        reset(seed) {
          const prng = PRNG(seed || Math.random() * 1e9);
          this.elapsed = 0;

          let rows = 15 + Math.floor(prng() * 6);
          let cols = 15 + Math.floor(prng() * 6);

          this.size.rows = rows;
          this.size.cols = cols;

          const maze = generateMaze(rows, cols, prng);

          let spawnR = Math.floor(prng() * rows);
          let spawnC = Math.floor(prng() * cols);
          while (true) {
            let exitR = Math.floor(prng() * rows);
            let exitC = Math.floor(prng() * cols);
            if (exitR !== spawnR || exitC !== spawnC) {
              this.exit = { r: exitR, c: exitC };
              break;
            }
          }

          this.spawn = { r: spawnR, c: spawnC };
          this.mazeData = maze;

          const directionOrders = [];
          for (let i = 0; i < 24; i++) {
            let dirs = ['n', 'e', 's', 'w'];
            let order = [...dirs];
            while (order.length) {
              let j = Math.floor(prng() * order.length);
              [order[0], order[j]] = [order[j], order[0]];
              order.shift();
            }
            directionOrders.push(order);
          }

          this.bots = [];
          for (let i = 0; i < 24; i++) {
            const bot = new Bot({ rows, cols }, { r: spawnR, c: spawnC }, directionOrders[i]);
            this.bots.push(bot);
          }
        },

        tick(n) {
          if (!this.mazeData) return;

          for (let i = 0; i < n; i++) {
            const currentTick = this.elapsed + 1;
            let allFinished = true;

            for (const bot of this.bots) {
              if (bot.finishedTick === null) {
                bot.update(this.mazeData, this.exit, currentTick);
                if (bot.finishedTick === null) {
                  allFinished = false;
                }
              }
            }

            const lastFinishTick = Math.max(...this.bots.map(b => b.finishedTick || -1));
            if (lastFinishTick === -1 || this.elapsed < lastFinishTick) {
              this.elapsed += 1;
            }

            render();
          }
        },

        walls(r, c) {
          return this.mazeData[r][c];
        }
      };

      function render() {
        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');
        const rows = window.game.size.rows;
        const cols = window.game.size.cols;
        const cellSize = Math.min(canvas.width / cols, canvas.height / rows);
        const spawn = window.game.spawn;
        const exit = window.game.exit;

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        for (let r = 0; r < rows; r++) {
          for (let c = 0; c < cols; c++) {
            const cell = window.game.mazeData[r][c];
            const x = c * cellSize;
            const y = r * cellSize;

            ctx.strokeStyle = 'black';
            if (cell.n) ctx.beginPath(), ctx.moveTo(x, y), ctx.lineTo(x + cellSize, y), ctx.stroke();
            if (cell.e) ctx.beginPath(), ctx.moveTo(x + cellSize, y), ctx.lineTo(x + cellSize, y + cellSize), ctx.stroke();
            if (cell.s) ctx.beginPath(), ctx.moveTo(x, y + cellSize), ctx.lineTo(x + cellSize, y + cellSize), ctx.stroke();
            if (cell.w) ctx.beginPath(), ctx.moveTo(x, y), ctx.lineTo(x, y + cellSize), ctx.stroke();
          }
        }

        const s = cellSize / 4;
        ctx.fillStyle = 'green';
        ctx.fillRect(spawn.c * cellSize + cellSize/2 - s, spawn.r * cellSize + cellSize/2 - s, s*2, s*2);
        ctx.fillStyle = 'red';
        ctx.fillRect(exit.c * cellSize + cellSize/2 - s, exit.r * cellSize + cellSize/2 - s, s*2, s*2);

        const botRadius = cellSize / 6;
        for (const bot of window.game.bots) {
          if (bot.finishedTick !== null) continue;

          const { r, c } = bot.currentCell;
          ctx.beginPath();
          ctx.arc(c * cellSize + cellSize/2, r * cellSize + cellSize/2, botRadius, 0, Math.PI*2);
          ctx.fillStyle = `hsl(${Math.random() * 360}, 100%, 50%)`;
          ctx.fill();
        }

        document.getElementById('completed').textContent = window.game.bots.filter(b => b.finishedTick !== null).length + '/24';
        document.getElementById('timer').textContent = window.game.elapsed;
      }

      document.getElementById('reset').addEventListener('click', () => {
        const seedInput = prompt("Enter seed (optional):");
        const seed = isNaN(seedInput) ? undefined : parseFloat(seedInput);
        window.game.reset(seed);
        render();
      });

      window.game.reset();
    })();
  </script>
</body>
</html>

