<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Maze Game</title>
    <style>
        body { font-family: sans-serif; text-align: center; }
        canvas { border: 1px solid #000; margin-top: 20px; }
        #timer, #completed { font-size: 1.5em; margin: 10px; }
    </style>
</head>
<body>
    <div id="timer">0</div>
    <div id="completed">0/24</div>
    <button id="reset">Reset</button>
    <canvas id="maze" width="400" height="400"></canvas>

    <script>
        const DIRECTIONS = ['n', 'e', 's', 'w'];
        let game;

        window.onload = () => {
            game = new Game(15, 15);
            document.getElementById('reset').onclick = () => game.reset();
        };

        class Game {
            constructor(rows, cols) {
                this.rows = rows;
                this.cols = cols;
                this.maze = null;
                this.bots = [];
                this.elapsed = 0;
                this.maxTicks = 20000;
                this.exit = { r: -1, c: -1 };
                this.spawn = { r: -1, c: -1 };
                this.reset();
            }

            reset(seed) {
                const rng = new RNG(seed || Math.random());
                this.maze = generateMaze(this.rows, this.cols, rng);
                [this.exit.r, this.exit.c] = getRandomCell(rng, this.rows, this.cols);
                while (JSON.stringify({ r: this.exit.r, c: this.exit.c }) === JSON.stringify(this.spawn)) {
                    [this.exit.r, this.exit.c] = getRandomCell(rng, this.rows, this.cols);
                }

                const startR = Math.floor(this.rows / 2), startC = Math.floor(this.cols / 2);
                this.spawn = { r: startR, c: startC };

                this.bots = [];
                for (let i = 0; i < 24; i++) {
                    const dirOrder = rotateDirections(DIRECTIONS, i % 4);
                    this.bots.push(new Bot(i, { r: startR, c: startC }, dirOrder));
                }

                this.elapsed = 0;
                for (let bot of this.bots) bot.finishTick = null;

                this.draw();
            }

            tick(n) {
                if (!this.maze || n <= 0) return;

                const finishTicksBefore = this.bots.filter(b => b.finishTick !== null).length === 24;
                for (let i = 0; i < n && !finishTicksBefore; i++) {
                    let allFinished = true;
                    for (let bot of this.bots) {
                        if (bot.finishTick !== null) continue;

                        const currentCell = bot.path[bot.position];
                        const cellWalls = this.maze.walls(currentCell.r, currentCell.c);
                        const possibleDirs = [];
                        for (const dir of bot.dirOrder) {
                            if (!cellWalls[dir]) possibleDirs.push(dir);
                        }

                        let nextDir = null;
                        for (let d of possibleDirs) {
                            const adj = getAdjacency(d, currentCell.r, currentCell.c);
                            if (adj && !bot.visited.has(adj)) {
                                nextDir = d;
                                break;
                            }
                        }

                        if (!nextDir) {
                            if (bot.position > 0) bot.position--;
                            continue;
                        }

                        const adj = getAdjacency(nextDir, currentCell.r, currentCell.c);
                        bot.path.push(adj);
                        bot.visited.add(adj);
                        bot.position++;

                        if (adj.r === this.exit.r && adj.c === this.exit.c) {
                            bot.finishTick = this.elapsed + i + 1;
                        }
                    }

                    allFinished = this.bots.every(b => b.finishTick !== null);
                    if (!allFinished) this.elapsed++;
                }

                this.draw();
            }

            draw() {
                const canvas = document.getElementById('maze');
                const ctx = canvas.getContext('2d');
                const cellSize = Math.min(canvas.width / this.cols, canvas.height / this.rows);

                // Clear
                ctx.clearRect(0, 0, canvas.width, canvas.height);

                // Draw maze walls
                for (let r = 0; r < this.rows; r++) {
                    for (let c = 0; c < this.cols; c++) {
                        const cellWalls = this.maze.walls(r, c);
                        ctx.strokeStyle = '#000';
                        if (cellWalls.n) ctx.beginPath(), ctx.moveTo(c * cellSize, r * cellSize), ctx.lineTo((c + 1) * cellSize, r * cellSize), ctx.stroke();
                        if (cellWalls.e) ctx.beginPath(), ctx.moveTo((c + 1) * cellSize, r * cellSize), ctx.lineTo((c + 1) * cellSize, (r + 1) * cellSize), ctx.stroke();
                        if (cellWalls.s) ctx.beginPath(), ctx.moveTo(c * cellSize, (r + 1) * cellSize), ctx.lineTo((c + 1) * cellSize, (r + 1) * cellSize), ctx.stroke();
                        if (cellWalls.w) ctx.beginPath(), ctx.moveTo(c * cellSize, r * cellSize), ctx.lineTo(c * cellSize, (r + 1) * cellSize), ctx.stroke();
                    }
                }

                // Draw exit
                const exitCell = this.exit;
                ctx.fillStyle = 'red';
                ctx.fillRect(exitCell.c * cellSize + cellSize / 4, exitCell.r * cellSize + cellSize / 4, cellSize / 2, cellSize / 2);

                // Draw bots
                for (let bot of this.bots) {
                    if (bot.finishTick !== null) continue;
                    const current = bot.path[bot.position];
                    ctx.fillStyle = bot.color;
                    ctx.beginPath();
                    ctx.arc(current.c * cellSize + cellSize / 2, current.r * cellSize + cellSize / 2, 5, 0, Math.PI * 2);
                    ctx.fill();
                }

                // Update UI
                document.getElementById('timer').textContent = this.elapsed;
                const completedCount = this.bots.filter(b => b.finishTick !== null).length;
                document.getElementById('completed').textContent = `${completedCount}/24`;
            }
        }

        class Bot {
            constructor(id, startCell, dirOrder) {
                this.id = id;
                this.color = `hsl(${id * 15}, 70%, 60%)`;
                this.path = [startCell];
                this.visited = new Set([JSON.stringify(startCell)]);
                this.position = 0; // index in path array
                this.dirOrder = dirOrder;
                this.finishTick = null;
            }
        }

        class Maze {
            constructor(rows, cols) {
                this.rows = rows;
                this.cols = cols;
                this.grid = Array.from({ length: rows }, () => Array(cols).fill().map(() => ({ n: true, e: true, s: true, w: true })));
            }

            walls(r, c) {
                return { ...this.grid[r][c] };
            }
        }

        function generateMaze(rows, cols, rng) {
            const maze = new Maze(rows, cols);
            const visited = Array.from({ length: rows }, () => Array(cols).fill(false));
            let stack = [];
            let r = Math.floor(rng.next() * rows), c = Math.floor(rng.next() * cols);
            visited[r][c] = true;
            stack.push([r, c]);

            while (stack.length > 0) {
                const [cr, cc] = stack[stack.length - 1];
                let found = false;

                // Try all directions
                const dirs = shuffle([...DIRECTIONS], rng);
                for (const dir of dirs) {
                    const [nr, nc] = getAdjacency(dir, cr, cc);
                    if (nr !== null && nc !== null && !visited[nr][nc]) {
                        found = true;
                        // Knock down walls
                        maze.grid[cr][cc][dir] = false;
                        const oppositeDir = { n: 's', e: 'w', s: 'n', w: 'e' }[dir];
                        maze.grid[nr][nc][oppositeDir] = false;
                        visited[nr][nc] = true;
                        stack.push([nr, nc]);
                        break;
                    }
                }

                if (!found) {
                    stack.pop();
                }
            }

            return maze;
        }

        function getAdjacency(dir, r, c) {
            switch (dir) {
                case 'n': return [r - 1, c];
                case 'e': return [r, c + 1];
                case 's': return [r + 1, c];
                case 'w': return [r, c - 1];
            }
            return null;
        }

        function getRandomCell(rng, rows, cols) {
            return [
                Math.floor(rng.next() * rows),
                Math.floor(rng.next() * cols)
            ];
        }

        function rotateDirections(arr, n) {
            const rotated = [...arr.slice(n), ...arr.slice(0, n)];
            return rotated;
        }

        function shuffle(array, rng) {
            for (let i = array.length - 1; i > 0; i--) {
                const j = Math.floor(rng.next() * (i + 1));
                [array[i], array[j]] = [array[j], array[i]];
            }
            return array;
        }

        class RNG {
            constructor(seed) {
                this.seed = seed % 2147483647;
                if (this.seed <= 0) this.seed += 2147483646;
            }

            next() {
                const m = 2147483647;
                const a = 16807;
                const c = 0;
                this.seed = (this.seed * a + c) % m;
                return this.seed / m;
            }
        }

        window.game = new Game(15, 15);
    </script>
</body>
</html>
